sp_widget.client_script:
function($scope, $location, $rootScope, spModal, spUtil) {
	//------------------------------------------------------------------------------------------------------------------------
	// COMPANY: DISCOVER TECHNOLOGIES
	// CUSTOMIZED BY: KARINA TORRES
	// RECURSIVE GRAPHICAL TREE FOR PROCESS TEMPLATE
	// HELPUL LINKS: https://gojs.net/latest/intro/textblocks.html
	//------------------------------------------------------------------------------------------------------------------------

	//------------------------------------------------------------------------------------------------------------------------
	// 2.5.21 | 09.08.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
	var node_active_bg = '#33738e';
	var node_inactive_bg = '#787878';
	var node_selected_border = '#FFD247';

	//------------------------------------------------------------------------------------------------------------------------

	var c = this;
	var currentPage = $scope.data.page_id;
	// STRY0069986 - move to top
	var display_id = $location.search().sys_id;
	// STRY0040294
	if (!display_id && c.data.id){
		display_id = c.data.id;
	}

	//  UI/UX - STRY0065140 - 2.5 Template List - FIX
	var diagram;


	// RJ - TUP - STRY0068618 - added run template
	$scope.runModalProcessTemplate = function() {


		spModal.open({
			title: 'Template Instance',
			backdrop: 'static',
			widget: 'discovertasker-widget-modal-prompt',
			widgetInput: {process_template_sys_id: $scope.data.templateId},
			size: 'lg',
			buttons: [{label:'Close', cancel: true}]
		}).then( function(){
			/* update model after return from modal */
			c.server.update();
		});
	};

$scope.openModalProcessTemplate = function() {

		/* opens the platform form in a modal for this table */
		// STRY0040294 - added isModal: true
		c.modalInstance = spModal.open({
				title: "Template Information",
				backdrop: 'static',
				widget: 'discovertasker-formtab',
				widgetInput: {table: 'x_153465_discovert_discover_routing_template',
											sys_id: $scope.data.templateId,
											isModal: true},
				size: 'lg',
				buttons: []
			});
};

	// STRY0040294 - use record watcher to keep grid synced
	spUtil.recordWatch($scope, "x_153465_discovert_route_tasks",
										 c.data.recordWatchFilter,
										 function(name, data) {
		spUtil.update($scope).then(function() {
			drawTree();	
		})
	});



	$rootScope.$on('dataTableClick', function (evt, item) { 

		$scope.data.id = item.sys_id;
		$scope.data.sys_id = item.sys_id;
		$scope.data.table = "x_153465_discovert_discover_routing_template"; //item.table;//"x_153465_discovert_route_tasks";


		//  UI/UX - STRY0065140 - 2.5 Template List - FIX
		if(item.process_level) c.data.process_level = item.process_level.display_value;
		if(item.template_name) c.data.name = item.template_name.display_value;

		$location.search('table', $scope.data.table).search('sys_id', $scope.data.sys_id).search('spa', 1);
		c.server.update().then(function(){
			drawTree();	
		});

	});

	$scope.$on('$taskerTabbedForm.list.click', function(e, parms) {
		c.data.sys_id = parms.sys_id;
		// STRY0074663 Only rebroadcast if the node changed
		if(display_id != parms.sys_id){
			display_id = parms.sys_id;	
			// Select the node using the sys_id parameter supplied.
			var node_select = diagram.findNodeForKey(display_id);
			diagram.select(node_select);
		}
	})

		function nodeSelectionChanged(node) { 

			var evt = {};
				var d = node.data;
				evt.sys_id = d.sys_id;

				if (evt.sys_id == display_id) { // get called twice by gojs
					return;
				}
				evt.table = d.sys_class_name || d.table;
				// RJ -ET - Story 4
				evt.parent = d.parent;

				display_id = evt.sys_id;
				$location.search('table', evt.table).search('sys_id', evt.sys_id).search('spa', 1);
				$rootScope.$broadcast('$sp.list.click', evt);
				// STRY0072032
				if(!c.data.isSystemTreeOrientationVertical){
					diagram.centerRect(node.actualBounds);
				}
		}

		$scope.page = {
				displayValue: $scope.data.title,
				value: $scope.data.id,
				name: 'page'
		};

	// STRY0069986 - one draw tree function, not 2 places with the same logic.
	if ($scope.data.id) { 
		drawTree();
	}

	function drawTree() {  
		//  UI/UX - STRY0065140 - 2.5 Template List - FIX
		if(diagram != undefined){
			diagram.div = null;
			diagram = null;
		}

			//setTimeout(function () {	
				var $go = go.GraphObject.make; // for conciseness in defining templates
				var node_id = "page_map_new";
				//jslog(diagram.div)

				if(currentPage == "discovertasker_processtemplatedetails" ){
									c.data.name = $scope.data.map[0].process_name_map;
									c.data.process_level = $scope.data.map[0].process_level_map;
				} 

				// STRY0072032
				if(!c.data.isSystemTreeOrientationVertical){
					// Horizontal Settings
					diagram = $go(go.Diagram, node_id, {
						allowVerticalScroll:false,
						//initialContentAlignment: go.Spot.Default,
						//allowZoom: false,
						// define the layout for the diagram
						layout: $go(go.TreeLayout, {
							nodeSpacing: 5,
							layerSpacing: 60
						})
					});
				} else{
					diagram = $go(go.Diagram, node_id, {
						initialAutoScale: go.Diagram.UniformToFill,
						// STRY0072032 trying takign this out for vertical, thinking we may need to allow vertical scroll
						// allowVerticalScroll:false,

						//initialContentAlignment: go.Spot.Default,
						//allowZoom: false,
						// define the layout for the diagram
						layout: $go(go.TreeLayout, {
							angle:90,
							nodeSpacing: 5,
							layerSpacing: 60
						})
					});

				}

				diagram.model = new go.TreeModel($scope.data.map);
				//var font = "12px SourceSansPro, Helvetica, Arial, sans-serif";
				var fontStyle = "13px Segoe UI";
				// Define a simple node template consisting of text followed by an expand/collapse button
				// STRY0072032
				var treeOrientation;
				if(!c.data.isSystemTreeOrientationVertical){
					treeOrientation = "Horizontal";
				} else {
					treeOrientation = "Vertical";
				}

				diagram.nodeTemplate = $go(go.Node, treeOrientation, {
						selectionAdorned: false,
						selectionChanged: nodeSelectionChanged,
						isTreeExpanded: true,
						isTreeLeaf: true
					}, // this event handler is defined below
					$go(go.Panel, "Auto",
						$go(go.Shape, "RoundedRectangle", {
								strokeWidth: 3
							}, {
								fill: "Gray"
							},
							new go.Binding("stroke", "isSelected", function (s) {
								if (s)
									return node_selected_border;
								else
									return null;
							}).ofObject(""),

							new go.Binding("fill", "active", function (t) { 
									switch(t){
										case "false":
											return node_inactive_bg;
										default:
											return node_active_bg;
									}
							})
						),
						$go(go.TextBlock, {
								font: fontStyle,
								stroke: "white",
								margin: 3,
								width: 200
							},
							new go.Binding("text", "name"))
					),
					$go("TreeExpanderButton") // this was overkill for small diagrams
				);
				if(c.selectedNode == null){
					c.selectedNode = $scope.data.map[0].sys_id;
				}
				diagram.select(diagram.findNodeForKey(display_id));
				// Define a trivial link template with no arrowhead
				// STRY0072032
				if(!c.data.isSystemTreeOrientationVertical){
					diagram.initialAutoScale=go.Diagram.Uniform;
				}
				//  UI/UX - STRY0065140 - 2.5 Template List - FIX
				diagram.allowVerticalScroll=false;
				diagram.linkTemplate = $go(go.Link, {
					selectable: false
				}, $go(go.Shape)); // the link shape
				// Resize the graph container height when the graph changes size
				diagram.addDiagramListener('DocumentBoundsChanged', function () {
					var diagramHeight = parseInt(diagram.documentBounds.height);
					jQuery("#" + node_id).height(diagramHeight);
				})
				// Select the node using the sys_id parameter supplied.
				var node_select = diagram.findNodeForKey(display_id);
				diagram.select(node_select);

			//}, 1000);
			//}
	}
	// only add the listner if data.id was set.
	if ($scope.data.id) { 
		// this event handler is called when the diagram is first ready
		diagram.addDiagramListener("InitialLayoutCompleted", function(e) {
			var node = diagram.findNodeForKey(display_id);
			// and center it and select it
			// STRY0072032
			if(c.data.isSystemTreeOrientationVertical){
				diagram.centerRect(node.actualBounds);
			}
		});
	}

}

